lines = []
# EnvironmentTab
lines.append('')
lines.append('// ─── ENVIRONMENT TAB (MP-06) ─────────────────────────────────────────────────')
lines.append('function EnvironmentTab({ envRecords, setEnvRecords }) {')
lines.append('  const [showAdd, setShowAdd] = useState(false);')
lines.append('  const [newRec, setNewRec] = useState({ date:"", location:"\u6f54\u6de8\u5ba4A\u5340", particles05:0, particles1:0, particles5:0, temp:22.0, humidity:45.0, pressure:12.5, operator:"", result:"\u5408\u683c" });')
lines.append('  const sorted = [...envRecords].sort((a,b) => new Date(b.date)-new Date(a.date));')
lines.append('  const resultColor = r => r==="\u5408\u683c"?"#22c55e":r==="\u8b66\u544a"?"#eab308":"#ef4444";')
lines.append('  function autoResult(rec) {')
lines.append('    const p05=parseInt(rec.particles05), p5=parseInt(rec.particles5), temp=parseFloat(rec.temp), hum=parseFloat(rec.humidity);')
lines.append('    if(p05>1000||p5>35||temp>23||temp<21||hum>50||hum<40) return "\u4e0d\u5408\u683c";')
lines.append('    if(p05>800||p5>20||temp>22.5||hum>48) return "\u8b66\u544a";')
lines.append('    return "\u5408\u683c";')
lines.append('  }')
lines.append('  function addRec() {')
lines.append('    const id = "ENV-" + String(envRecords.length+1).padStart(3,"0");')
lines.append('    const result = autoResult(newRec);')
lines.append('    setEnvRecords(prev => [...prev, { ...newRec, id, result, particles05:parseInt(newRec.particles05), particles1:parseInt(newRec.particles1), particles5:parseInt(newRec.particles5), temp:parseFloat(newRec.temp), humidity:parseFloat(newRec.humidity), pressure:parseFloat(newRec.pressure) }]);')
lines.append('    setShowAdd(false);')
lines.append('    setNewRec({ date:"", location:"\u6f54\u6de8\u5ba4A\u5340", particles05:0, particles1:0, particles5:0, temp:22.0, humidity:45.0, pressure:12.5, operator:"", result:"\u5408\u683c" });')
lines.append('  }')
lines.append('  const recent = sorted.slice(0,9);')
lines.append('  const passRate = envRecords.length>0?Math.round(envRecords.filter(r=>r.result==="\u5408\u683c").length/envRecords.length*100):0;')
lines.append('  return (')
lines.append('    <div>')
lines.append('      <SectionHeader title="\u5de5\u4f5c\u74b0\u5883\u76e3\u63a7\uff08MP-06\uff09" count={envRecords.length} color="#14b8a6" />')
lines.append('      <div style={{ display: "flex", gap: 12, marginBottom: 20, flexWrap: "wrap" }}>')
lines.append('        <StatCard label="\u76e3\u6e2c\u7e3d\u7b46\u6578" value={envRecords.length} color="#14b8a6" />')
lines.append('        <StatCard label="\u5408\u683c\u7b46\u6578" value={envRecords.filter(r=>r.result==="\u5408\u683c").length} color="#22c55e" />')
lines.append('        <StatCard label="\u8b66\u544a\u7b46\u6578" value={envRecords.filter(r=>r.result==="\u8b66\u544a").length} color="#eab308" />')
lines.append('        <StatCard label="\u4e0d\u5408\u683c\u7b46\u6578" value={envRecords.filter(r=>r.result==="\u4e0d\u5408\u683c").length} color="#ef4444" />')
lines.append('        <StatCard label="\u6574\u9ad4\u5408\u683c\u7387" value={`${passRate}%`} color={passRate>=90?"#22c55e":passRate>=80?"#eab308":"#ef4444"} sub="\u5168\u671f\u76e3\u6e2c\u8a08" />')
lines.append('      </div>')
lines.append('      <div style={{ background: "rgba(20,184,166,0.06)", border: "1px solid rgba(20,184,166,0.2)", borderRadius: 12, padding: 16, marginBottom: 20 }}>')
lines.append('        <div style={{ fontSize: 13, color: "#2dd4bf", fontWeight: 700, marginBottom: 8 }}>\U0001f3ed \u6f54\u6de8\u5ba4 Class 1000 \u6a19\u6e96\u6307\u5f15</div>')
lines.append('        <div style={{ display:"flex", gap:24, flexWrap:"wrap", fontSize:12, color:"#64748b" }}>')
lines.append('          <span>\u2265 0.5\u03bcm\u7c92\u5b50\uff1a\u2264 1,000 \u500b/\u7acb\u65b9\u5c3a\u5c3a</span>')
lines.append('          <span>\u2265 5\u03bcm\u7c92\u5b50\uff1a\u2264 35 \u500b/\u7acb\u65b9\u5c3a\u5c3a</span>')
lines.append('          <span>\u6eab\u5ea6\uff1a21\u201323\u00b0C</span>')
lines.append('          <span>\u6fd5\u5ea6\uff1a40\u201350% RH</span>')
lines.append('          <span>\u6b63\u58d3\uff1a\u2265 10 Pa</span>')
lines.append('        </div>')
lines.append('      </div>')
lines.append('      <div style={{ display:"flex", justifyContent:"flex-end", marginBottom:14 }}>')
lines.append('        <button onClick={() => setShowAdd(true)} style={{ background: "linear-gradient(135deg, #0d9488, #14b8a6)", border:"none", borderRadius:10, color:"#fff", cursor:"pointer", padding:"9px 18px", fontSize:13, fontWeight:700 }}>\uff0b \u65b0\u589e\u76e3\u6e2c\u7d00\u9304</button>')
lines.append('      </div>')
lines.append('      <div style={{ overflowX:"auto" }}>')
lines.append('        <table style={{ width:"100%", borderCollapse:"collapse", fontSize:12 }}>')
lines.append('          <thead><tr>{["\u7de8\u865f","\u65e5\u671f","\u5730\u9ede","\u2265 0.5\u03bcm","\u2265 1\u03bcm","\u2265 5\u03bcm","\u6eab\u5ea6(\u00b0C)","\u6fd5\u5ea6(%)","\u6b63\u58d3(Pa)","\u8a18\u9304\u8005","\u7d50\u679c"].map(h => (<th key={h} style={{ textAlign:"left", padding:"8px 10px", color:"#64748b", fontWeight:600, borderBottom:"1px solid rgba(255,255,255,0.06)", whiteSpace:"nowrap" }}>{h}</th>))}</tr></thead>')
lines.append('          <tbody>')
lines.append('            {sorted.map((r,i) => (')
lines.append('              <tr key={r.id} style={{ background:i%2===0?"rgba(255,255,255,0.02)":"transparent" }}>')
lines.append('                <td style={{ padding:"8px 10px", color:"#14b8a6", fontFamily:"monospace" }}>{r.id}</td>')
lines.append('                <td style={{ padding:"8px 10px", color:"#94a3b8", whiteSpace:"nowrap" }}>{formatDate(r.date)}</td>')
lines.append('                <td style={{ padding:"8px 10px", color:"#e2e8f0" }}>{r.location}</td>')
lines.append('                <td style={{ padding:"8px 10px", color:r.particles05>1000?"#ef4444":r.particles05>800?"#eab308":"#94a3b8", fontWeight:r.particles05>800?700:400 }}>{r.particles05.toLocaleString()}</td>')
lines.append('                <td style={{ padding:"8px 10px", color:"#94a3b8" }}>{r.particles1.toLocaleString()}</td>')
lines.append('                <td style={{ padding:"8px 10px", color:r.particles5>35?"#ef4444":r.particles5>20?"#eab308":"#94a3b8", fontWeight:r.particles5>20?700:400 }}>{r.particles5}</td>')
lines.append('                <td style={{ padding:"8px 10px", color:r.temp>23||r.temp<21?"#ef4444":"#94a3b8" }}>{r.temp.toFixed(1)}</td>')
lines.append('                <td style={{ padding:"8px 10px", color:r.humidity>50||r.humidity<40?"#ef4444":"#94a3b8" }}>{r.humidity.toFixed(1)}</td>')
lines.append('                <td style={{ padding:"8px 10px", color:r.pressure<10?"#ef4444":"#94a3b8" }}>{r.pressure.toFixed(1)}</td>')
lines.append('                <td style={{ padding:"8px 10px", color:"#94a3b8" }}>{r.operator}</td>')
lines.append('                <td style={{ padding:"8px 10px" }}><Badge color={resultColor(r.result)}>{r.result}</Badge></td>')
lines.append('              </tr>')
lines.append('            ))}')
lines.append('          </tbody>')
lines.append('        </table>')
lines.append('      </div>')
lines.append('      {showAdd && (<Modal title="\u65b0\u589e\u74b0\u5883\u76e3\u6e2c\u7d00\u9304" onClose={() => setShowAdd(false)}><div style={{ display:"flex", flexDirection:"column", gap:12 }}>{[["\u76e3\u6e2c\u65e5\u671f","date","date"],["\u8a18\u9304\u8005","operator","text"],["\u2265 0.5\u03bcm \u500b\u6578","particles05","number"],["\u2265 1\u03bcm \u500b\u6578","particles1","number"],["\u2265 5\u03bcm \u500b\u6578","particles5","number"],["\u6eab\u5ea6 (\u00b0C)","temp","number"],["\u6fd5\u5ea6 (%)","humidity","number"],["\u6b63\u58d3 (Pa)","pressure","number"]].map(([label,field,type]) => (<div key={field}><div style={{ fontSize:12, color:"#64748b", marginBottom:5 }}>{label}</div><input type={type} value={newRec[field]} onChange={e=>setNewRec({...newRec,[field]:e.target.value})} step={type==="number"?"0.1":undefined} style={inputStyle} /></div>))}<div style={{ background:"rgba(20,184,166,0.1)", borderRadius:8, padding:10, fontSize:12, color:"#2dd4bf" }}>\ud83d\udd0d \u7cfb\u7d71\u5c07\u6839\u64da\u76e3\u6e2c\u6578\u636e\u81ea\u52d5\u5224\u5b9a\u7d50\u679c\uff08\u5408\u683c/\u8b66\u544a/\u4e0d\u5408\u683c\uff09</div><button onClick={addRec} style={{ background:"linear-gradient(135deg,#0d9488,#14b8a6)", border:"none", borderRadius:10, color:"#fff", cursor:"pointer", padding:"12px 24px", fontSize:15, fontWeight:700, marginTop:8 }}>\u2713 \u5132\u5b58\u76e3\u6e2c\u7d00\u9304</button></div></Modal>)}')
lines.append('    </div>')
lines.append('  );')
lines.append('}')

content = '\n'.join(lines) + '\n'
with open(r'C:\Users\USER\Desktop\自動稽核程式\audit-dashboard.jsx', 'a', encoding='utf-8-sig') as f:
    f.write(content)
print('Part7 EnvironmentTab OK')
